    -fx-font-size: 28px;
    -fx-font-weight: 700;
}

.nav-item,
.nav-sub-item {
    -fx-background-color: transparent;
    -fx-text-fill: #f0f2ff;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-alignment: CENTER_LEFT;
    -fx-padding: 9 14 9 14;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-cursor: hand;
}

.nav-sub-item {
