}

.search-field {
    -fx-background-color: #f4f5f7;
    -fx-border-color: #c8cdd7;
    -fx-border-radius: 6;
    -fx-background-radius: 6;
    -fx-padding: 0 10 0 10;
}

.table-search {
    -fx-background-color: linear-gradient(to bottom, #f8fafb 0%, #f3f6fa 100%);
    -fx-border-color: #d0d9ea;
    -fx-border-radius: 12;
    -fx-background-radius: 12;
    -fx-padding: 11 14 11 14;
    -fx-font-size: 13px;
    -fx-margin: 0 0 8 0;
    -fx-text-fill: #1f3149;
    -fx-effect: dropshadow(gaussian, rgba(70, 100, 160, 0.08), 8, 0.08, 0, 2);
}

.table-search:focused {
    -fx-border-color: #5a8aff;
    -fx-effect: dropshadow(gaussian, rgba(90, 138, 255, 0.18), 12, 0.10, 0, 3);
}

.table-search:hover {
